115	func (m DashboardModel) handleKey(msg tea.KeyMsg) (DashboardModel, tea.Cmd) {
116		// If session picker is active, handle picker keys
117		if m.pickerActive {
118			return m.handlePickerKey(msg)
119		}
120	
121		switch msg.String() {
122		case "s":
123			m.visible = false
124			return m, nil
125		case "esc":
126			m.visible = false
127			return m, nil
128		case "r":
129			m.Refresh(m.session)
130			return m, nil
131		case "1":
132			m.pickerActive = true
133			m.pickerCursor = 0
