139	func (m DashboardModel) handlePickerKey(msg tea.KeyMsg) (DashboardModel, tea.Cmd) {
140		switch msg.String() {
141		case "esc":
142			m.pickerActive = false
143			return m, nil
144		case "1":
145			m.pickerActive = false
146			return m, nil
147		case "j", "down":
148			if m.pickerCursor < len(m.sessions)-1 {
149				m.pickerCursor++
150			}
151			return m, nil
152		case "k", "up":
153			if m.pickerCursor > 0 {
154				m.pickerCursor--
155			}
156			return m, nil
157		case "enter":
158			if m.pickerCursor >= 0 && m.pickerCursor < len(m.sessions) {
159				sel := m.sessions[m.pickerCursor]
