209	func (m DashboardModel) renderContent() string {
210		switch m.state {
211		case StateLoading:
212			return i18n.T("status.loading")
213		case StateEmpty:
214			return i18n.T("status.empty")
215		case StateError:
216			errText := fmt.Sprintf("%s: %s", i18n.T("status.error"), m.errMsg)
217			return lipgloss.NewStyle().Foreground(lipgloss.Color("196")).Render(errText)
218		case StatePopulated:
219			return m.renderDashboard()
220		}
221		return ""
222	}
