224	// toolBarEntry is used for sorted bar chart rendering.
225	type toolBarEntry struct {
226		Name  string
227		Count int
228		Pct   float64
229	}
230	
231	func (m DashboardModel) renderDashboard() string {
232		if m.stats == nil {
233			return i18n.T("status.empty")
234		}
235	
236		var b strings.Builder
237	
238		// Header: Total Duration and Peak Step
239		totalDurLabel := i18n.T("dashboard.total_duration")
240		totalDur := formatDuration(m.stats.TotalDuration)
241		b.WriteString(fmt.Sprintf("%s: %s", totalDurLabel, totalDur))
242	
243		peakLabel := i18n.T("dashboard.peak_step")
244		peak := m.stats.PeakStep
245		if peak.ToolName != "" {
246			peakStr := fmt.Sprintf("%s (%s)", peak.ToolName, formatDuration(peak.Duration))
247			// Highlight in yellow if slow (>= 30s)
248			if peak.Duration >= 30*time.Second {
249				peakStr = lipgloss.NewStyle().Foreground(lipgloss.Color("226")).Render(peakStr)
250			}
251			b.WriteString(fmt.Sprintf("          %s: %s", peakLabel, peakStr))
252		}
253		b.WriteString("\n\n")
254	
255		// Build sorted entries from stats
256		entries := make([]toolBarEntry, 0, len(m.stats.ToolCallCounts))
257		for name, count := range m.stats.ToolCallCounts {
258			pct := m.stats.ToolTimePcts[name]
259			entries = append(entries, toolBarEntry{Name: name, Count: count, Pct: pct})
260		}
261		sort.Slice(entries, func(i, j int) bool {
262			if entries[i].Count != entries[j].Count {
263				return entries[i].Count > entries[j].Count
264			}
265			return entries[i].Name < entries[j].Name
266		})
267	
268		// Calculate available width for bars
269		labelWidth := 10                                           // max tool name width
270		countWidth := 6                                            // e.g., "  12"
271		availBarWidth := m.width - 4 - labelWidth - countWidth - 6 // padding
272		if availBarWidth < 5 {
273			availBarWidth = 5
274		}
275	
276		// Tool Calls header
277		toolStatsLabel := i18n.T("dashboard.tool_stats")
278		timeStatsLabel := i18n.T("dashboard.time_stats")
279		b.WriteString(fmt.Sprintf("%-20s %s\n", toolStatsLabel, timeStatsLabel))
280	
281		// Find max count for scaling
282		maxCount := 0
283		for _, e := range entries {
284			if e.Count > maxCount {
285				maxCount = e.Count
286			}
287		}
288	
289		// Render each tool entry
290		for _, entry := range entries {
291			// Count bar: Ō¢ł chars proportional to count
292			barLen := 0
293			if maxCount > 0 {
294				barLen = entry.Count * availBarWidth / maxCount
295			}
296			if barLen < 1 && entry.Count > 0 {
297				barLen = 1
298			}
299			countBar := strings.Repeat("Ō¢ł", barLen)
300			countStr := fmt.Sprintf("%-10s %s %d", entry.Name, countBar, entry.Count)
301	
302			// Percentage bar: Ō¢łŌ¢æ chars proportional to percentage
303			pctBarWidth := 8
304			filled := int(entry.Pct / 100 * float64(pctBarWidth))
305			if filled < 1 && entry.Pct > 0 {
306				filled = 1
307			}
308			if filled > pctBarWidth {
309				filled = pctBarWidth
310			}
311			pctBar := strings.Repeat("Ō¢ł", filled) + strings.Repeat("Ō¢æ", pctBarWidth-filled)
312			pctStr := fmt.Sprintf("%-10s %s %3.0f%%", entry.Name, pctBar, entry.Pct)
313	
314			b.WriteString(fmt.Sprintf("%s   %s\n", countStr, pctStr))
315		}
316	
317		return b.String()
318	}
319	
320	func (m DashboardModel) renderPicker() string {
321		if len(m.sessions) == 0 {
322			return i18n.T("picker.no_results")
323		}
324	
325		// Determine picker dimensions
326		pickerWidth := m.width / 4
327		if pickerWidth < 25 {
328			pickerWidth = 25
329		}
330		pickerHeight := len(m.sessions) + 2 // title + sessions
331		if pickerHeight > 12 {
332			pickerHeight = 12
333		}
334	
335		pickerStyle := lipgloss.NewStyle().
336			BorderForeground(lipgloss.Color("51")). // bright cyan when focused
337			Border(lipgloss.RoundedBorder()).
338			Width(pickerWidth - 2).
339			Height(pickerHeight - 2)
340	
341		title := i18n.T("picker.title")
342	
343		var b strings.Builder
344		for i, s := range m.sessions {
345			dateStr := s.Date.Format("2006-01-02")
346			calls := fmt.Sprintf("%4d", s.ToolCount)
347			durStr := formatDuration(s.Duration)
348	
349			marker := "  "
350			if i == m.pickerCursor {
351				marker = "Ō¢Ė "
352			}
353	
354			row := fmt.Sprintf("%s%s %s %s", marker, dateStr, calls, durStr)
355	
356			if i == m.pickerCursor {
357				style := lipgloss.NewStyle().
358					Foreground(lipgloss.Color("15")).
359					Background(lipgloss.Color("55"))
360				b.WriteString(style.Render(row))
361			} else {
362				b.WriteString(lipgloss.NewStyle().Foreground(lipgloss.Color("252")).Render(row))
363			}
364	
365			if i < len(m.sessions)-1 {
366				b.WriteString("\n")
367			}
368		}
369	
370		titleStr := lipgloss.NewStyle().Bold(true).Foreground(lipgloss.Color("15")).Render(title)
371		return pickerStyle.Render(titleStr + "\n" + b.String())
372	}
