func padColLine(lines []string, i, colWidth int) string {
    if i < len(lines) {
        return lines[i]
    }
    return strings.Repeat(" ", colWidth)
}

func max3(a, b, c int) int {
    m := a
    if b > m { m = b }
    if c > m { m = c }
    return m
}

func truncateName(name string, maxLen int) string {
    runes := []rune(name)
    if len(runes) <= maxLen {
