    mutedStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("240"))

    lines := []string{headerStyle.Render("Skill")}

    if len(stats.SkillCounts) == 0 {
        lines = append(lines, mutedStyle.Render("(none)"))
        return lines
    }

    entries := sortedEntries(stats.SkillCounts)
    limit := 10
    shown := entries
    extra := 0
    if len(entries) > limit {
        shown = entries[:limit]
        extra = len(entries) - limit
    }

    for _, e := range shown {
        name := truncateName(e.Name, 22)
        line := fmt.Sprintf("%-22s %4d", name, e.Count)
        lines = append(lines, normalStyle.Render(line))
    }
    if extra > 0 {
        lines = append(lines, mutedStyle.Render(fmt.Sprintf("... +%d more", extra)))
    }

    return lines
}

func renderMCPCol(stats *parser.SessionStats, colWidth int) []string {
    headerStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("51"))
    normalStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("252"))
    dimStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("242"))
    mutedStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("240"))

    lines := []string{headerStyle.Render("MCP *")}

    if len(stats.MCPServers) == 0 {
        lines = append(lines, mutedStyle.Render("(none)"))
        return lines
    }

    // Sort servers by total desc, name asc on tie
    type serverEntry struct {
        Name  string
        Stats *parser.MCPServerStats
    }
    servers := make([]serverEntry, 0, len(stats.MCPServers))
    for k, v := range stats.MCPServers {
        servers = append(servers, serverEntry{k, v})
    }
    sort.Slice(servers, func(i, j int) bool {
        if servers[i].Stats.Total != servers[j].Stats.Total {
            return servers[i].Stats.Total > servers[j].Stats.Total
