type skillEntry struct {
    name  string
    count int
}

func sortedSkillEntries(counts map[string]int) []skillEntry {
    entries := make([]skillEntry, 0, len(counts))
    for name, count := range counts {
        entries = append(entries, skillEntry{name, count})
    }
    sort.Slice(entries, func(i, j int) bool {
        if entries[i].count != entries[j].count {
            return entries[i].count > entries[j].count
        }
        return entries[i].name < entries[j].name
    })
    return entries
}

func (m DashboardModel) buildSkillColLines(colWidth int) []string {
    headerStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("51"))
    normalStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("252"))
    mutedStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("240"))

    lines := []string{headerStyle.Render("Skill")}

    if len(m.stats.SkillCounts) == 0 {
        lines = append(lines, mutedStyle.Render("(none)"))
        return lines
    }

    entries := sortedSkillEntries(m.stats.SkillCounts)
    nameWidth := colWidth - 5
    if nameWidth < 5 {
        nameWidth = 5
    }

    shown := entries
    extra := 0
    if len(entries) > 10 {
        shown = entries[:10]
        extra = len(entries) - 10
    }

    for _, e := range shown {
        name := truncateName(e.name, nameWidth)
        line := fmt.Sprintf("%-*s %4d", nameWidth, name, e.count)
        lines = append(lines, normalStyle.Render(line))
    }
    if extra > 0 {
        lines = append(lines, mutedStyle.Render(fmt.Sprintf("... +%d more", extra)))
    }
    return lines
}

