func TestRenderSkillCol_NameTruncated(t *testing.T) {
	longName := strings.Repeat("a", 30)
	s := statsWithSkills(map[string]int{longName: 1})
	lines := renderSkillCol(s, 30)
	// Name should be truncated to 22 chars with ellipsis
