func TestRenderMCPCol_ServerSortedByTotal(t *testing.T) {
	s := statsWithMCP(map[string]*parser.MCPServerStats{
		"low":  {Total: 1, Tools: map[string]int{"t": 1}},
		"high": {Total: 5, Tools: map[string]int{"t": 5}},
	})
	lines := renderMCPCol(s, 30)
