	tools := map[string]int{}
	for i := 0; i < 8; i++ {
		tools[strings.Repeat("t", i+1)] = 8 - i
	}
	s := statsWithMCP(map[string]*parser.MCPServerStats{
		"srv": {Total: 36, Tools: tools},
